#!/usr/bin/env node
'use strict';

/**
 * scripts/canonicalize-meta-files.js
 *
 * #246 PR A -- one-shot rewrite of `data/terapeak/*.meta` companion files
 * to the canonical search-term convention. This eliminates the *source* of
 * dataset-key duplication identified by `scripts/audit-duplicate-keys.js`:
 * different `.meta` files generated by different placeholder scripts used
 * different country prefixes ("Great Britain" vs "British", "South Africa"
 * vs no country) for the same coin, producing two cache keys per coin.
 *
 * Canonical convention (matches existing CSV-filename style):
 *   - Britannia: "<year> British <metal> Britannia 1oz"
 *     (was: "<year> Great Britain 1 oz <metal> Britannia")
 *   - Krugerrand: "<year> Gold Krugerrand 1oz"
 *     (was: "<year> South Africa(n) 1 oz Gold Krugerrand")
 *
 * SAFETY:
 *   - Only rewrites .meta files whose content matches one of the documented
 *     long-form patterns. All other .meta files are left untouched.
 *   - --dry-run (default OFF) for preview.
 *   - Prints a per-file change log.
 *   - Does NOT touch `data/terapeak-meta.json` or Cosmos. Historical
 *     duplicates in the cache are addressed separately by
 *     `scripts/prune-ghost-keys.js`.
 *
 * Usage:
 *   node scripts/canonicalize-meta-files.js --dry-run    # preview
 *   node scripts/canonicalize-meta-files.js              # apply
 */

const fs = require('fs');
const path = require('path');

const META_DIR = path.join(__dirname, '..', 'data', 'terapeak');
const DRY_RUN = process.argv.includes('--dry-run');

// Fractional ounce word forms (must match normalizeSearchKey's vocabulary).
const FRAC_MAP = {
  '1/2': 'Half', '1/4': 'Quarter', '1/10': 'Tenth', '1/20': 'Twentieth',
};
function fracWord(token) {
  return FRAC_MAP[token] || null;
}

// Each rule: { name, match, rewrite } where `rewrite` returns the new
// content or null/unchanged if the rule doesn't apply.
const RULES = [
  {
    // 1oz Britannia, year-prefixed.
    // "<year> Great Britain 1 oz <metal> Britannia" -> "<year> British <metal> Britannia 1oz"
    name: 'britannia: 1oz year-prefixed -- Great Britain -> British, collapse "1 oz", reorder',
    match: /^(\d{4})\s+Great\s+Britain\s+1\s*oz\s+(Gold|Silver|Platinum)\s+Britannia\s*$/i,
    rewrite: (s) => s.replace(
      /^(\d{4})\s+Great\s+Britain\s+1\s*oz\s+(Gold|Silver|Platinum)\s+Britannia\s*$/i,
      (_, year, metal) => {
        const m = metal.charAt(0).toUpperCase() + metal.slice(1).toLowerCase();
        return `${year} British ${m} Britannia 1oz`;
      }
    ),
  },
  {
    // Fractional Britannia, year-prefixed.
    // "<year> Great Britain 1/N oz <metal> Britannia" -> "<year> British <metal> Britannia <Word> oz"
    name: 'britannia: fractional year-prefixed -- Great Britain -> British, fraction-to-word, reorder',
    match: /^(\d{4})\s+Great\s+Britain\s+(1\/(?:2|4|10|20))\s*oz\s+(Gold|Silver|Platinum)\s+Britannia\s*$/i,
    rewrite: (s) => {
      const m = s.match(/^(\d{4})\s+Great\s+Britain\s+(1\/(?:2|4|10|20))\s*oz\s+(Gold|Silver|Platinum)\s+Britannia\s*$/i);
      if (!m) return s;
      const [, year, frac, metal] = m;
      const word = fracWord(frac);
      if (!word) return s;
      const me = metal.charAt(0).toUpperCase() + metal.slice(1).toLowerCase();
      return `${year} British ${me} Britannia ${word} oz`;
    },
  },
  {
    // Generic fractional Britannia, no year.
    // "Great Britain 1/N oz <metal> Britannia" -> "British <metal> Britannia <Word> oz Generic"
    name: 'britannia: fractional generic -- Great Britain -> British, fraction-to-word, append Generic',
    match: /^Great\s+Britain\s+(1\/(?:2|4|10|20))\s*oz\s+(Gold|Silver|Platinum)\s+Britannia\s*$/i,
    rewrite: (s) => {
      const m = s.match(/^Great\s+Britain\s+(1\/(?:2|4|10|20))\s*oz\s+(Gold|Silver|Platinum)\s+Britannia\s*$/i);
      if (!m) return s;
      const [, frac, metal] = m;
      const word = fracWord(frac);
      if (!word) return s;
      const me = metal.charAt(0).toUpperCase() + metal.slice(1).toLowerCase();
      return `British ${me} Britannia ${word} oz Generic`;
    },
  },
  {
    // 1oz Krugerrand.
    // "<year> South Africa(n) 1 oz Gold Krugerrand" -> "<year> Gold Krugerrand 1oz"
    name: 'krugerrand: drop "South Africa(n)", collapse "1 oz", reorder',
    match: /^(\d{4})\s+South\s+Africa(n)?\s+1\s*oz\s+Gold\s+Krugerrand\s*$/i,
    rewrite: (s) => s.replace(
      /^(\d{4})\s+South\s+Africa(n)?\s+1\s*oz\s+Gold\s+Krugerrand\s*$/i,
      (_, year) => `${year} Gold Krugerrand 1oz`
    ),
  },
];

function applyRules(content) {
  for (const rule of RULES) {
    if (rule.match.test(content)) {
      const next = rule.rewrite(content);
      if (next && next !== content) return { next, rule: rule.name };
    }
  }
  return null;
}

function main() {
  if (!fs.existsSync(META_DIR)) {
    console.error(`[canonicalize] meta directory not found: ${META_DIR}`);
    process.exit(1);
  }

  const files = fs.readdirSync(META_DIR).filter(f => f.endsWith('.meta'));
  console.log(`[canonicalize] Scanning ${files.length} .meta files in ${META_DIR}`);
  console.log(`[canonicalize] Mode: ${DRY_RUN ? 'DRY-RUN (no writes)' : 'APPLY (writes will occur)'}`);
  console.log('');

  const changes = [];
  const byRule = {};

  for (const file of files) {
    const filePath = path.join(META_DIR, file);
    const original = fs.readFileSync(filePath, 'utf8').replace(/\s+$/, '');
    const result = applyRules(original);
    if (!result) continue;

    changes.push({ file, original, next: result.next, rule: result.rule });
    byRule[result.rule] = (byRule[result.rule] || 0) + 1;

    if (!DRY_RUN) {
      // Preserve no-trailing-newline convention (existing .meta files have none)
      fs.writeFileSync(filePath, result.next);
    }
  }

  console.log(`[canonicalize] Files to change: ${changes.length}`);
  console.log('');
  console.log('Per-rule counts:');
  for (const [rule, count] of Object.entries(byRule)) {
    console.log(`  ${String(count).padStart(4)}  ${rule}`);
  }
  console.log('');

  const sample = changes.slice(0, 10);
  console.log(`First ${sample.length} changes:`);
  for (const c of sample) {
    console.log(`  ${c.file}`);
    console.log(`    - ${JSON.stringify(c.original)}`);
    console.log(`    + ${JSON.stringify(c.next)}`);
  }
  if (changes.length > sample.length) {
    console.log(`  ... and ${changes.length - sample.length} more`);
  }
  console.log('');

  if (DRY_RUN) {
    console.log('[canonicalize] Dry-run complete. Re-run without --dry-run to apply.');
  } else {
    console.log(`[canonicalize] Wrote ${changes.length} file(s).`);
  }
}

main();
